func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const REGRET_K = 3 // number of top candidates considered for regret computation
	type candidate struct {
		assignIdx int
		costDelta float64
		ok        bool
	}
	orderCount := len(oris)
	if orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for orderID := 0; orderID < orderCount; orderID++ {
		ori := oris[orderID]
		des := dess[orderID]
		shipKey := total_ship + orderID
		topCandidates := make([]candidate, 0, dispatch.AssignsLen+1)
		// Evaluate all existing assigns
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			oldCost := dispatch.Assigns[ai].Cost
			if dispatch.Assigns[ai].AddShip(shipKey, ori, des) {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				delta := newCost - oldCost
				if newCost >= 0 && oldCost >= 0 {
					topCandidates = append(topCandidates, candidate{ai, delta, true})
				}
				dispatch.Assigns[ai].RemoveShip(shipKey)
				dispatch.Assigns[ai].GenRoute()
			}
		}
		// Evaluate potential new assign slot
		if dispatch.AssignsLen < MAXASSIGNS {
			ai := dispatch.AssignsLen
			if dispatch.Assigns[ai].AddShip(shipKey, ori, des) {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				if newCost >= 0 {
					delta := newCost - 0.0
					topCandidates = append(topCandidates, candidate{ai, delta, true})
				}
				dispatch.Assigns[ai].RemoveShip(shipKey)
				dispatch.Assigns[ai].GenRoute()
			}
		}
		var bestCand candidate
		bestCand.ok = false
		if len(topCandidates) > 0 {
			// Sort by costDelta ascending
			for i := 0; i < len(topCandidates)-1; i++ {
				for j := i + 1; j < len(topCandidates); j++ {
					if topCandidates[i].costDelta > topCandidates[j].costDelta {
						topCandidates[i], topCandidates[j] = topCandidates[j], topCandidates[i]
					}
				}
			}
			k := REGRET_K
			if k > len(topCandidates) {
				k = len(topCandidates)
			}
			if k == 1 {
				bestCand = topCandidates[0]
			} else {
				regretScore := -1e18
				for i := 0; i < k; i++ {
					secondBest := topCandidates[1].costDelta
					if k > 1 && i == 0 {
						secondBest = topCandidates[1].costDelta
					} else if k > 1 && i > 0 {
						secondBest = topCandidates[0].costDelta
					} else {
						secondBest = topCandidates[i].costDelta
					}
					score := secondBest - topCandidates[i].costDelta
					if score > regretScore {
						regretScore = score
						bestCand = topCandidates[i]
					}
				}
				// Tie-breaker: pick smallest costDelta among top regret ties
				minDelta := bestCand.costDelta
				finalPick := bestCand
				for i := 0; i < k; i++ {
					score2 := topCandidates[1].costDelta - topCandidates[i].costDelta
					if k > 1 && i == 0 {
						score2 = topCandidates[1].costDelta - topCandidates[0].costDelta
					} else if k > 1 && i > 0 {
						score2 = topCandidates[0].costDelta - topCandidates[i].costDelta
					}
					if score2 == regretScore && topCandidates[i].costDelta < minDelta {
						minDelta = topCandidates[i].costDelta
						finalPick = topCandidates[i]
					}
				}
				bestCand = finalPick
			}
		}
