			stationsBackup := make([]Station, len(dispatch.Assigns[ai].Stations))
			copy(stationsBackup, dispatch.Assigns[ai].Stations[:dispatch.Assigns[ai].StationsLen])
			slenBackup := dispatch.Assigns[ai].StationsLen
			// Trial insert
			if dispatch.Assigns[ai].AddShip(shipKey, ori, des) {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				delta := newCost - oldCost
				// Accept positive-cost insertion if feasible; lower delta is better
				if newCost >= 0 {
					if !bestCand.ok || delta < bestCand.costDelta {
						bestCand.assignIdx = ai
						bestCand.costDelta = delta
						bestCand.ok = true
					}
				}
				// Rollback
				dispatch.Assigns[ai].RemoveShip(shipKey)
				copy(dispatch.Assigns[ai].Stations[:], stationsBackup)
				dispatch.Assigns[ai].StationsLen = slenBackup
				dispatch.Assigns[ai].GenRoute()
			}
		}
